import{_ as a,c as t,o as s,a5 as i}from"./chunks/framework.CgT1UzWm.js";const u=JSON.parse('{"title":"DISABLED Annotation","titleTemplate":"NpgsqlRest","description":"Disable a PostgreSQL function or procedure as an HTTP endpoint without dropping or modifying the routine itself.","frontmatter":{"outline":[2,3],"title":"DISABLED Annotation","titleTemplate":"NpgsqlRest","description":"Disable a PostgreSQL function or procedure as an HTTP endpoint without dropping or modifying the routine itself.","head":[["meta",{"name":"keywords","content":"npgsqlrest disabled, disable endpoint, hide api endpoint"}],["meta",{"property":"og:title","content":"NpgsqlRest DISABLED Annotation"}],["meta",{"property":"og:description","content":"Disable a function or procedure from being exposed as an HTTP endpoint."}],["meta",{"property":"og:type","content":"article"}]]},"headers":[],"relativePath":"annotations/disabled.md","filePath":"annotations/disabled.md"}'),n={name:"annotations/disabled.md"};function o(l,e,d,r,c,p){return s(),t("div",null,e[0]||(e[0]=[i(`<h1 id="disabled" tabindex="-1">DISABLED <a class="header-anchor" href="#disabled" aria-label="Permalink to &quot;DISABLED&quot;">​</a></h1><p>Hide a routine from being exposed as an HTTP endpoint without dropping or modifying it.</p><h2 id="keywords" tabindex="-1">Keywords <a class="header-anchor" href="#keywords" aria-label="Permalink to &quot;Keywords&quot;">​</a></h2><p><code>@disabled</code>, <code>disabled</code></p><h2 id="syntax" tabindex="-1">Syntax <a class="header-anchor" href="#syntax" aria-label="Permalink to &quot;Syntax&quot;">​</a></h2><details class="code-collapsible" open><summary>code</summary><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes catppuccin-latte catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>@disabled</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div></details><p>The endpoint will not be created. The function or procedure remains in the database, callable directly via SQL — only the HTTP exposure is suppressed.</p><h2 id="example" tabindex="-1">Example <a class="header-anchor" href="#example" aria-label="Permalink to &quot;Example&quot;">​</a></h2><details class="code-collapsible" open><summary>sql</summary><div class="language-sql vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes catppuccin-latte catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">comment on function deprecated_func() is </span><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;">&#39;</span></span>
<span class="line"><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;">HTTP</span></span>
<span class="line"><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;">@disabled&#39;</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div></details><p><code>deprecated_func</code> is not registered as an HTTP endpoint at startup. Useful for:</p><ul><li>Temporarily hiding an endpoint without removing the function</li><li>Keeping a routine that&#39;s called internally from other functions but should not be reachable over HTTP</li><li>Disabling old endpoints during a deprecation cycle while leaving the function around for rollback</li></ul><h2 id="tag-conditional-form" tabindex="-1">Tag-conditional form <a class="header-anchor" href="#tag-conditional-form" aria-label="Permalink to &quot;Tag-conditional form&quot;">​</a></h2><details class="code-collapsible" open><summary>code</summary><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes catppuccin-latte catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>@disabled &lt;tag1&gt;, &lt;tag2&gt;, ...</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div></details><p>Disables the endpoint only when the routine matches at least one of the listed tags. The available auto-tags assigned by <code>RoutineSource</code> are:</p><div class="table-container"><div class="table-wrapper"><table tabindex="0"><thead><tr><th>Tag</th><th>Matches</th></tr></thead><tbody><tr><td><code>function</code></td><td>PostgreSQL functions</td></tr><tr><td><code>procedure</code></td><td>PostgreSQL procedures</td></tr><tr><td><code>volatile</code></td><td>Functions declared <code>VOLATILE</code> (the default)</td></tr><tr><td><code>stable</code></td><td>Functions declared <code>STABLE</code></td></tr><tr><td><code>immutable</code></td><td>Functions declared <code>IMMUTABLE</code></td></tr><tr><td><code>other</code></td><td>Procedures (volatility doesn&#39;t apply)</td></tr></tbody></table></div></div><details class="code-collapsible" open><summary>sql</summary><div class="language-sql vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes catppuccin-latte catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#9CA0B0;--shiki-light-font-style:italic;--shiki-dark:#6C7086;--shiki-dark-font-style:italic;">-- Disable only if the function is volatile (e.g., to enforce read-only API surface)</span></span>
<span class="line"><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">comment on function get_data() is </span><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;">&#39;</span></span>
<span class="line"><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;">HTTP GET</span></span>
<span class="line"><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;">@disabled volatile&#39;</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div></details><p>Custom tags are not supported — only the auto-tags above are available. SQL file endpoints have no auto-tags.</p><div class="tip custom-block"><p class="custom-block-title">Most projects don&#39;t need the tag form</p><p>The unconditional <code>@disabled</code> is the form you&#39;ll reach for in practice. The tag form is a leftover from earlier versions where the CRUD source assigned per-operation tags (<code>select</code>, <code>insert</code>, etc.).</p></div><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./enabled.html">ENABLED</a> — re-enable inside a tag-scoped block</li><li><a href="./tags.html">TAGS</a> — apply annotations conditionally by routine tag</li><li><a href="./internal.html">INTERNAL</a> — alternative for marking a routine as internal-only</li></ul>`,20)]))}const m=a(n,[["render",o]]);export{u as __pageData,m as default};
